//! High-level statistical modeling API for Rust
//!
//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
//! and `Glm` (Generalized Linear Models), integrating lower-level crates
//! to provide a complete modeling workflow.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use faer::{prelude::*, Mat};

/// Statistical modeling errors
#[derive(thiserror::Error, Debug)]
pub enum ModelError {
    /// Linear algebra computation error
    #[error("Linear algebra error: {0}")]
    LinearAlgebra(String),
    /// Invalid model specification
    #[error("Invalid model: {0}")]
    InvalidModel(String),
}

/// Common trait for all fitted models
pub trait Fit {
    /// Get model coefficients
    fn coefficients(&self) -> &[f64];

    /// Get fitted values
    fn fitted(&self) -> &[f64];

    /// Get residuals
    fn residuals(&self) -> &[f64];

    /// Get model summary
    fn summary(&self) -> ModelSummary;
}

/// Model summary information
#[derive(Debug)]
pub struct ModelSummary {
    /// Coefficient table
    pub coefficients: Vec<CoefficientRow>,
    /// R-squared (coefficient of determination)
    pub r_squared: f64,
    /// Adjusted R-squared
    pub adj_r_squared: f64,
    /// Residual standard error
    pub residual_std_error: f64,
    /// F-statistic for overall model significance
    pub f_statistic: f64,
    /// p-value for F-statistic
    pub f_p_value: f64,
    /// Degrees of freedom for model (number of predictors excluding intercept)
    pub df_model: usize,
    /// Degrees of freedom for residuals
    pub df_residual: usize,
}

/// A row in the coefficient table
#[derive(Debug)]
pub struct CoefficientRow {
    /// Variable name
    pub name: String,
    /// Estimated coefficient
    pub estimate: f64,
    /// Standard error
    pub std_error: f64,
    /// t-statistic
    pub t_value: f64,
    /// p-value
    pub p_value: f64,
}

/// Linear model fitting
pub struct Lm;

/// Fitted linear model results
#[derive(Debug)]
pub struct LmFit {
    coefficients: Vec<f64>,
    fitted_values: Vec<f64>,
    residuals: Vec<f64>,
    /// Number of observations
    n_obs: usize,
    /// Matrix rank (for rank-deficient matrices)
    rank: usize,
    /// Design matrix for statistical inference (stored for covariance calculation)
    x_matrix: Mat<f64>,
}

impl Lm {
    /// Fit a linear model using QR decomposition with column pivoting
    ///
    /// This implementation uses faer's column-pivoted QR decomposition to handle
    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    pub fn fit(
        x_data: &[f64],
        y_data: &[f64],
        n_rows: usize,
        n_cols: usize,
    ) -> Result<LmFit, ModelError> {
        if x_data.len() != n_rows * n_cols {
            return Err(ModelError::InvalidModel(
                "Design matrix dimensions don't match data".to_string(),
            ));
        }

        if y_data.len() != n_rows {
            return Err(ModelError::InvalidModel(
                "Response vector length doesn't match number of observations".to_string(),
            ));
        }

        // Create faer matrices from input data
        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);

        // Use column-pivoted QR for numerical stability with rank-deficient matrices
        let qr = x_mat.col_piv_qr();

        // Calculate rank from R matrix diagonal elements
        let r_matrix = qr.R();
        let tolerance = 1e-12;
        let mut rank = 0;
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            if r_matrix[(i, i)].abs() > tolerance {
                rank += 1;
            }
        }

        // Handle rank-deficient matrices by checking for numerical instability
        let coefficients_mat = qr.solve_lstsq(&y_mat);

        // Check for numerical instability and apply correction if needed
        let has_instability =
            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);

        let final_coefficients_mat = if has_instability {
            // For rank-deficient case, set coefficients for columns beyond rank to zero
            let mut corrected_coefs = Vec::new();
            for i in 0..coefficients_mat.nrows() {
                let coef = coefficients_mat[(i, 0)];
                if coef.abs() > 1e10 {
                    corrected_coefs.push(0.0);
                } else {
                    corrected_coefs.push(coef);
                }
            }
            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
        } else {
            coefficients_mat
        };

        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
        let fitted_mat = &x_mat * &final_coefficients_mat;

        // Calculate residuals: e = y - ŷ
        let residuals_mat = &y_mat - &fitted_mat;

        // Extract results to plain Vec<f64> for API
        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
            .map(|i| final_coefficients_mat[(i, 0)])
            .collect();

        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
            .map(|i| fitted_mat[(i, 0)])
            .collect();

        let residuals: Vec<f64> = (0..residuals_mat.nrows())
            .map(|i| residuals_mat[(i, 0)])
            .collect();

        // rank is already computed above using qr.rank()

        Ok(LmFit {
            coefficients,
            fitted_values,
            residuals,
            n_obs: n_rows,
            rank,
            x_matrix: x_mat,
        })
    }
}

impl LmFit {
    /// Get the number of observations used in the model
    pub fn n_obs(&self) -> usize {
        self.n_obs
    }

    /// Get the rank of the design matrix (number of linearly independent columns)
    pub fn rank(&self) -> usize {
        self.rank
    }

    /// Get degrees of freedom for error (n_obs - rank)
    pub fn df_resid(&self) -> usize {
        self.n_obs.saturating_sub(self.rank)
    }
}

impl Fit for LmFit {
    fn coefficients(&self) -> &[f64] {
        &self.coefficients
    }

    fn fitted(&self) -> &[f64] {
        &self.fitted_values
    }

    fn residuals(&self) -> &[f64] {
        &self.residuals
    }

    fn summary(&self) -> ModelSummary {
        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};

        // Calculate residual standard error: s² = RSS / (n - p)
        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
        let df_resid = self.df_resid() as f64;
        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
        let residual_std_error = mse.sqrt();

        // Calculate Total Sum of Squares (TSS) and R-squared
        let y_mean: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
            .sum::<f64>()
            / self.n_obs as f64;

        let tss: f64 = self
            .fitted_values
            .iter()
            .zip(self.residuals.iter())
            .map(|(fitted, resid)| {
                let y = fitted + resid;
                (y - y_mean).powi(2)
            })
            .sum();

        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };

        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
        let n = self.n_obs as f64;
        let p = self.rank as f64;
        let adj_r_squared = if n > 1.0 && p > 0.0 {
            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
        } else {
            r_squared
        };

        // F-statistic for overall model significance
        // RSS for null model (intercept only) equals TSS
        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
        let f_statistic = if df_model > 0 {
            model_f_statistic(rss, tss, df_model, self.df_resid())
        } else {
            0.0
        };

        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
        } else {
            1.0
        };

        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
        // Compute X'X
        let xtx = self.x_matrix.transpose() * &self.x_matrix;

        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
        let qr = xtx.col_piv_qr();
        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
        let xtx_inv = qr.solve(&identity);

        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
        let std_errors: Vec<f64> = (0..self.coefficients.len())
            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
            .collect();

        let t_stats = t_statistics(&self.coefficients, &std_errors);
        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);

        let mut coefficient_rows = Vec::new();
        for (i, &coef) in self.coefficients.iter().enumerate() {
            let name = if i == 0 {
                "Intercept".to_string()
            } else {
                format!("X{}", i)
            };

            coefficient_rows.push(CoefficientRow {
                name,
                estimate: coef,
                std_error: std_errors[i],
                t_value: t_stats[i],
                p_value: p_values[i],
            });
        }

        ModelSummary {
            coefficients: coefficient_rows,
            r_squared,
            adj_r_squared,
            residual_std_error,
            f_statistic,
            f_p_value,
            df_model,
            df_residual: self.df_resid(),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_lm_fit_basic() {
        // Simple 2x2 identity matrix with response
        let x_data = vec![1.0, 0.0, 0.0, 1.0]; // 2x2 identity
        let y_data = vec![1.0, 2.0];

        let result = Lm::fit(&x_data, &y_data, 2, 2);
        assert!(result.is_ok());

        let fit = result.unwrap();
        assert_eq!(fit.coefficients().len(), 2);
        assert_eq!(fit.fitted().len(), 2);
        assert_eq!(fit.residuals().len(), 2);
        assert_eq!(fit.n_obs, 2);
        assert_eq!(fit.rank, 2);
    }

    #[test]
    fn test_lm_simple_regression() {
        // Simple linear regression: y = 1 + 2*x + error
        // Design matrix with intercept column
        let x_data = vec![
            1.0, 1.0, // [1, x1]
            1.0, 2.0, // [1, x2]
            1.0, 3.0, // [1, x3]
        ];
        let y_data = vec![3.0, 5.0, 7.0]; // 1 + 2*x

        let result = Lm::fit(&x_data, &y_data, 3, 2);
        assert!(result.is_ok());

        let fit = result.unwrap();

        // Check that we recovered the true coefficients (approximately)
        let coefs = fit.coefficients();
        assert!(
            (coefs[0] - 1.0).abs() < 1e-10,
            "Intercept should be ~1.0, got {}",
            coefs[0]
        );
        assert!(
            (coefs[1] - 2.0).abs() < 1e-10,
            "Slope should be ~2.0, got {}",
            coefs[1]
        );

        // Check dimensions
        assert_eq!(fit.n_obs, 3);
        assert_eq!(fit.rank, 2);
    }

    #[test]
    fn test_lm_rank_deficient() {
        // Rank deficient matrix: second column = 2 * first column
        let x_data = vec![
            1.0, 2.0, // [1, 2]
            2.0, 4.0, // [2, 4]
            3.0, 6.0, // [3, 6]
        ];
        let y_data = vec![1.0, 2.0, 3.0];

        let result = Lm::fit(&x_data, &y_data, 3, 2);
        assert!(result.is_ok());

        let fit = result.unwrap();

        // Matrix rank should be correctly detected as 1 (second column = 2 * first column)
        assert_eq!(fit.n_obs(), 3);
        assert_eq!(fit.rank(), 1); // Correctly detected rank-deficient matrix
        assert_eq!(fit.df_resid(), 2); // 3 obs - 1 rank = 2 df

        // The key is that coefficients should still be computed without crashing
        assert_eq!(fit.coefficients().len(), 2);
    }

    #[test]
    fn test_lm_summary() {
        // Use a case with some residual variation for meaningful standard errors
        let x_data = vec![
            1.0, 1.0, // [1, x1]
            1.0, 2.0, // [1, x2]
            1.0, 3.0, // [1, x3]
            1.0, 4.0, // [1, x4]
        ];
        let y_data = vec![2.1, 4.0, 5.9, 8.1]; // approximately y = 2*x with some noise

        let fit = Lm::fit(&x_data, &y_data, 4, 2).unwrap();
        let summary = fit.summary();

        assert!(!summary.coefficients.is_empty());
        assert_eq!(summary.coefficients[0].name, "Intercept");
        assert_eq!(summary.coefficients.len(), 2);

        // Verify that standard errors are computed (not zero or placeholder)
        for coef_row in &summary.coefficients {
            assert!(
                coef_row.std_error > 0.0,
                "Standard error should be positive: {}",
                coef_row.std_error
            );
            assert!(
                coef_row.p_value >= 0.0 && coef_row.p_value <= 1.0,
                "P-value should be between 0 and 1"
            );
        }
    }

    #[test]
    fn test_statistical_inference_known_case() {
        // Simple case: y = 1 + 2*x (exact linear relationship)
        let x_data = vec![
            1.0, 1.0, // [1, x1] where x1 = 1
            1.0, 2.0, // [1, x2] where x2 = 2
            1.0, 3.0, // [1, x3] where x3 = 3
        ];
        let y_data = vec![3.0, 5.0, 7.0]; // y = 1 + 2*x

        let fit = Lm::fit(&x_data, &y_data, 3, 2).unwrap();
        let summary = fit.summary();

        // With perfect linear fit, residuals should be very small
        assert!(
            fit.residuals().iter().all(|&r| r.abs() < 1e-10),
            "Residuals should be near zero for perfect fit"
        );

        // Coefficients should be exactly recovered
        let coefs = fit.coefficients();
        assert!((coefs[0] - 1.0).abs() < 1e-10, "Intercept should be 1.0");
        assert!((coefs[1] - 2.0).abs() < 1e-10, "Slope should be 2.0");

        // For perfect fit with 1 degree of freedom, statistics should be extreme
        assert_eq!(summary.coefficients.len(), 2);
        println!("Summary: {:?}", summary);
    }

    #[test]
    fn test_enhanced_summary_statistics() {
        // Test with data that has some variation for meaningful R²
        let x_data = vec![
            1.0, 1.0, // [1, x1]
            1.0, 2.0, // [1, x2]
            1.0, 3.0, // [1, x3]
            1.0, 4.0, // [1, x4]
            1.0, 5.0, // [1, x5]
        ];
        let y_data = vec![2.1, 3.9, 6.1, 7.9, 10.1]; // approximately y = 2*x with noise

        let fit = Lm::fit(&x_data, &y_data, 5, 2).unwrap();
        let summary = fit.summary();

        // Verify enhanced summary includes all R-parity statistics
        assert!(
            summary.r_squared >= 0.0 && summary.r_squared <= 1.0,
            "R² should be between 0 and 1"
        );
        assert!(
            summary.adj_r_squared <= summary.r_squared,
            "Adjusted R² should be ≤ R²"
        );
        assert!(
            summary.residual_std_error > 0.0,
            "Residual standard error should be positive"
        );
        assert!(
            summary.f_statistic >= 0.0,
            "F-statistic should be non-negative"
        );
        assert!(
            summary.f_p_value >= 0.0 && summary.f_p_value <= 1.0,
            "F p-value should be between 0 and 1"
        );
        assert_eq!(
            summary.df_model, 1,
            "Model should have 1 degree of freedom (excluding intercept)"
        );
        assert_eq!(
            summary.df_residual, 3,
            "Should have 3 residual degrees of freedom (5 obs - 2 params)"
        );

        // With decent fit, R² should be reasonably high
        assert!(
            summary.r_squared > 0.8,
            "R² should be high for this near-linear relationship: {}",
            summary.r_squared
        );

        println!("Enhanced summary statistics:");
        println!("R² = {:.6}", summary.r_squared);
        println!("Adj R² = {:.6}", summary.adj_r_squared);
        println!("Residual SE = {:.6}", summary.residual_std_error);
        println!("F-statistic = {:.6}", summary.f_statistic);
        println!("F p-value = {:.6}", summary.f_p_value);
    }

    #[test]
    fn test_multicollinearity_debug() {
        // Test with non-collinear data to check if our fix works
        let n_obs = 8;
        let x1_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();
        let x2_values: Vec<f64> = (1..=n_obs)
            .map(|i| (i as f64) * 0.3 + 0.1 * (i as f64).powi(2))
            .collect();
        let y_values: Vec<f64> = x1_values
            .iter()
            .zip(x2_values.iter())
            .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
            .collect();

        // Design matrix: [1, x1, x2] - now without perfect multicollinearity
        let mut x_data = Vec::with_capacity(n_obs * 3);
        for i in 0..n_obs {
            x_data.push(1.0); // intercept
            x_data.push(x1_values[i]); // x1
            x_data.push(x2_values[i]); // x2
        }

        println!("=== Multiple Regression Debug ===");
        println!("x1: {:?}", x1_values);
        println!("x2: {:?}", x2_values);
        println!("x2 is not perfectly correlated with x1");

        let x_mat = Mat::from_fn(n_obs, 3, |i, j| x_data[i * 3 + j]);
        let _y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);

        println!("Design matrix X (first 3 rows):");
        for i in 0..3 {
            println!(
                "  [{}, {}, {}]",
                x_mat[(i, 0)],
                x_mat[(i, 1)],
                x_mat[(i, 2)]
            );
        }

        let qr = x_mat.col_piv_qr();
        let r_matrix = qr.R();

        println!("R matrix diagonal:");
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            println!("  R[{},{}] = {}", i, i, r_matrix[(i, i)]);
        }

        // Detect rank
        let tolerance = 1e-12;
        let mut rank = 0;
        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
            if r_matrix[(i, i)].abs() > tolerance {
                rank += 1;
            }
        }
        println!("Detected rank: {} (should be 3 for full rank)", rank);

        let fit = Lm::fit(&x_data, &y_values, n_obs, 3).unwrap();
        println!("Our coefficients: {:?}", fit.coefficients());
        println!("Our rank: {}", fit.rank());

        // Check if coefficients are numerically stable
        for (i, &coef) in fit.coefficients().iter().enumerate() {
            if coef.abs() > 1e6 {
                println!(
                    "WARNING: Coefficient {} is numerically unstable: {}",
                    i, coef
                );
            }
        }
    }
}

