//! Simple R comparison benchmark
//!
//! Validates we're meeting 2x speed target vs R's lm()

use criterion::{criterion_group, criterion_main, Criterion};
use stats_models::Lm;

fn generate_test_data(n_obs: usize, n_vars: usize) -> (Vec<f64>, Vec<f64>) {
    let mut x_data = Vec::with_capacity(n_obs * n_vars);
    let mut y_data = Vec::with_capacity(n_obs);

    for i in 0..n_obs {
        // Intercept
        x_data.push(1.0);
        // Variables
        for j in 1..n_vars {
            x_data.push((i as f64 + j as f64) * 0.1);
        }
        // Response
        let y = 1.0
            + (0..n_vars - 1)
                .map(|j| (i as f64 + j as f64) * 0.1 * 0.5)
                .sum::<f64>();
        y_data.push(y);
    }

    (x_data, y_data)
}

