/// Build the final design matrix with optimized memory layout
pub fn build(self) -> Array2<f64> {
    if self.columns.is_empty() {
        return Array2::zeros((self.n_rows, 0));
    }

    let n_cols = self.columns.len();

    // Pre-allocate flat vector for row-major construction
    let mut data = vec![0.0; self.n_rows * n_cols];

    // Parallel processing of columns into flat array
    self.columns
        .par_iter()
        .enumerate()
        .for_each(|(col_idx, column)| {
            for (row_idx, &value) in column.iter().enumerate() {
                // Calculate index for row-major layout
                let flat_idx = row_idx * n_cols + col_idx;
                // This is safe because we pre-allocated the exact size needed
                unsafe {
                    *data.get_unchecked_mut(flat_idx) = value;
                }
            }
        });

    // Convert to ndarray with correct shape
    Array2::from_shape_vec((self.n_rows, n_cols), data)
        .expect("Shape and data length should match")
}

