    fn test_missing_variable_error() {
        let formula_spec = parse_formula("y ~ x").unwrap();
        let data = DataContainer::new(3); // No variables added

        let result = build_design_matrix(&formula_spec, &data);
        assert!(result.is_err());
        assert!(matches!(
            result.unwrap_err(),
            MatrixError::VariableNotFound(_)
        ));
    }

    #[test]
    fn test_dimension_mismatch_error() {
        let mut data = DataContainer::new(3);
        let wrong_length = vec![1.0, 2.0]; // Length 2, but expected 3

        let result = data.add_variable("x".to_string(), wrong_length);
        assert!(result.is_err());
        assert!(matches!(result.unwrap_err(), MatrixError::Dimension(_)));
    }
}

